CREATE TABLE `ai_usage` (
  `id` int NOT NULL AUTO_INCREMENT,
  `tenant_id` varchar(50) COLLATE utf8mb4_unicode_ci NOT NULL,
  `year` int NOT NULL,
  `month` int NOT NULL,
  `used_count` int DEFAULT '0',
  `plan` varchar(50) COLLATE utf8mb4_unicode_ci DEFAULT 'FREE',
  PRIMARY KEY (`id`),
  UNIQUE KEY `tenant_year_month` (`tenant_id`,`year`,`month`)
) ENGINE=InnoDB AUTO_INCREMENT=2 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

LOCK TABLES `ai_usage` WRITE;

UNLOCK TABLES;

CREATE TABLE `allocation_links` (
  `id` bigint NOT NULL AUTO_INCREMENT,
  `created_at` datetime(6) NOT NULL DEFAULT CURRENT_TIMESTAMP(6),
  `updated_at` datetime(6) NOT NULL DEFAULT CURRENT_TIMESTAMP(6) ON UPDATE CURRENT_TIMESTAMP(6),
  `tenant_id` varchar(36) COLLATE utf8mb4_unicode_ci NOT NULL,
  `source_reference_number` varchar(150) COLLATE utf8mb4_unicode_ci NOT NULL,
  `source_reference_type` varchar(20) COLLATE utf8mb4_unicode_ci NOT NULL,
  `source_reference_date` date DEFAULT NULL,
  `target_reference_number` varchar(150) COLLATE utf8mb4_unicode_ci NOT NULL,
  `target_reference_type` varchar(20) COLLATE utf8mb4_unicode_ci NOT NULL,
  `amount_applied` decimal(15,2) NOT NULL,
  PRIMARY KEY (`id`),
  KEY `idx_alloc_link_source` (`tenant_id`,`source_reference_number`,`source_reference_type`),
  KEY `idx_alloc_link_target` (`tenant_id`,`target_reference_number`,`target_reference_type`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

LOCK TABLES `allocation_links` WRITE;

UNLOCK TABLES;

CREATE TABLE `amount_transactions` (
  `id` bigint NOT NULL AUTO_INCREMENT,
  `tenant_id` varchar(36) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL,
  `created_at` datetime(6) DEFAULT NULL,
  `updated_at` datetime(6) DEFAULT NULL,
  `transaction_date` date NOT NULL,
  `transaction_type` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'transaction',
  `debit` decimal(15,2) NOT NULL DEFAULT '0.00',
  `credit` decimal(15,2) NOT NULL DEFAULT '0.00',
  `balance` decimal(15,2) NOT NULL DEFAULT '0.00',
  `narration` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci,
  `ledger_id` bigint NOT NULL,
  `ledger_name` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT 'Ledger name (e.g., bank2, Cash, HDFC Bank)',
  `sub_group_1` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `code` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `voucher_id` bigint DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `tenant_id` (`tenant_id`),
  KEY `amount_tran_tenant__d7c201_idx` (`tenant_id`,`ledger_id`,`transaction_date`),
  KEY `amount_tran_tenant__9534d3_idx` (`tenant_id`,`transaction_type`),
  KEY `amount_tran_transac_10f4ee_idx` (`transaction_date`)
) ENGINE=InnoDB AUTO_INCREMENT=4 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

LOCK TABLES `amount_transactions` WRITE;

