  `date` date NOT NULL,
  `voucher_number` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL,
  `receipt_rows` json DEFAULT NULL,
  `posting_note` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci,
