  `advance_amount` decimal(15,2) DEFAULT '0.00',
  `transaction_details` json DEFAULT NULL COMMENT 'List: [{date, invoiceNo, amount, receiveNow, pending, advance}]',
  `created_at` datetime(6) DEFAULT CURRENT_TIMESTAMP(6),
